exercise.solution:
interface BlogPost {
  readonly id: number;
  title: string;
  subtitle?: string;
  published: boolean;
  tags: string[];
}

function summarize(post: BlogPost): string {
  return `[${post.id}] ${post.title} — ${post.tags.length} tag(s)`;
}

const post: BlogPost = {
  id: 42,
  title: "Hello TypeScript",
  published: true,
  tags: ["ts", "tutorial", "beginners"],
};

console.log(summarize(post));
